using System.ComponentModel;
using System.Net;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build IChatClient through the MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---
var tools = new AITool[]
{
    AIFunctionFactory.Create(ResearchTools.SearchWeb),
    AIFunctionFactory.Create(ResearchTools.SaveNote),
    AIFunctionFactory.Create(ResearchTools.GetNotes),
};

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to research a topic the user provides.

        Workflow:
        1. Break the topic into 2-3 focused search queries.
        2. Use the SearchWeb tool for each query.
        3. After each search, use SaveNote to record key findings with a short title.
        4. After gathering enough information, use GetNotes to review everything you collected.
        5. Produce a final summary that synthesizes all your notes into a clear, well-structured answer.

        Always cite which searches contributed to your findings.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

// --- Run the agent ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var session = new ChatClientAgentSession();

await foreach (var update in agent.RunStreamingAsync(topic, session, runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine($"Research complete. {ResearchTools.NoteCount} note(s) saved during research.");

