// Tools
// =============================================================================

/// <summary>
/// Tools available to the research agent for web searching and note-taking.
/// </summary>
static class ResearchTools
{
    private static readonly List<(string Title, string Content)> _notes = [];
    private static readonly HttpClient _httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    public static int NoteCount => _notes.Count;

    [Description("Searches the web for the given query and returns a summary of results.")]
    public static async Task<string> SearchWeb(
        [Description("The search query to look up on the web.")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            // Use DuckDuckGo lite (HTML) — no API key required
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://lite.duckduckgo.com/lite?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("User-Agent", "ResearchAgent/1.0");

            using var response = await _httpClient.SendAsync(request);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync();

            // Extract text snippets from the HTML result rows
            var snippets = ExtractSnippets(html);

            if (snippets.Count == 0)
            {
                return $"No results found for \"{query}\".";
            }

            return $"Search results for \"{query}\":\n\n" +
                   string.Join("\n\n", snippets.Select((s, i) => $"{i + 1}. {s}"));
        }
        catch (Exception ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}";
        }
    }

    [Description("Saves a research note with a title and content for later reference.")]
    public static string SaveNote(
        [Description("A short title for the note.")] string title,
        [Description("The content/findings to save.")] string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note \"{title}\" saved successfully ({_notes.Count} total notes).";
    }

    [Description("Retrieves all saved research notes collected so far.")]
    public static string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        Console.WriteLine($"  📋 Reviewing {_notes.Count} note(s)");

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note {i + 1}: {n.Title} ---\n{n.Content}"));
    }

    private static List<string> ExtractSnippets(string html)
    {
        var snippets = new List<string>();

        // DuckDuckGo lite returns results in table rows with class "result-snippet"
        var parts = html.Split("<td class=\"result-snippet\">",
            StringSplitOptions.RemoveEmptyEntries);

        for (int i = 1; i < parts.Length && snippets.Count < 6; i++)
        {
            var endIdx = parts[i].IndexOf("</td>", StringComparison.Ordinal);
            if (endIdx <= 0)
            {
                continue;
            }

            var snippet = parts[i][..endIdx];

            // Strip HTML tags
            snippet = System.Text.RegularExpressions.Regex.Replace(snippet, "<[^>]+>", "");
            snippet = WebUtility.HtmlDecode(snippet).Trim();

            if (snippet.Length > 20)
            {
                snippets.Add(snippet);
            }
        }

        return snippets;
    }
}

