160.     private static List<string> ExtractSnippets(string html)
161.     {
162.         var snippets = new List<string>();
163. 
164.         // DuckDuckGo lite returns results in table rows with class "result-snippet"
165.         var parts = html.Split("<td class=\"result-snippet\">",
166.             StringSplitOptions.RemoveEmptyEntries);
167. 
168.         for (int i = 1; i < parts.Length && snippets.Count < 6; i++)
169.         {
170.             var endIdx = parts[i].IndexOf("</td>", StringComparison.Ordinal);
171.             if (endIdx <= 0)
172.             {
173.                 continue;
174.             }
175. 
176.             var snippet = parts[i][..endIdx];
177. 
178.             // Strip HTML tags
179.             snippet = System.Text.RegularExpressions.Regex.Replace(snippet, "<[^>]+>", "");
180.             snippet = WebUtility.HtmlDecode(snippet).Trim();
181. 
182.             if (snippet.Length > 20)
183.             {
184.                 snippets.Add(snippet);
185.             }
186.         }
187. 
188.         return snippets;
